func TestFormatResourceAddress(t *testing.T) {
	tests := []struct {
		name     string
		addr     addrs.AbsResourceInstance
		expected string
	}{
		{
			name: "managed resource in root module",
			addr: addrs.AbsResourceInstance{
				Module: addrs.RootModuleInstance,
				Resource: addrs.ResourceInstance{
					Resource: addrs.Resource{
						Mode: addrs.ManagedResourceMode,
						Type: "aws_instance",
						Name: "example",
					},
				},
			},
			expected: "aws_instance.example",
		},
		{
			name: "data source in root module",
			addr: addrs.AbsResourceInstance{
				Module: addrs.RootModuleInstance,
				Resource: addrs.ResourceInstance{
					Resource: addrs.Resource{
						Mode: addrs.DataResourceMode,
						Type: "aws_ami",
						Name: "ubuntu",
					},
				},
			},
			expected: "data.aws_ami.ubuntu",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			output := formatResourceAddress(tt.addr)
			if output != tt.expected {
				t.Errorf("formatResourceAddress() = %q, want %q", output, tt.expected)
			}
		})
	}
}

func TestGetActionSymbol(t *testing.T) {
	tests := []struct {
		action   plans.Action
		expected string
	}{
		{plans.Create, "[+]"},
		{plans.Update, "[~]"},
		{plans.Delete, "[-]"},
		{plans.DeleteThenCreate, "[-/+]"},
		{plans.CreateThenDelete, "[+/-]"},
		{plans.Read, "[<=]"},
		{plans.Forget, "[.]"},
		{plans.CreateThenForget, "[+/.]"},
	}

	for _, tt := range tests {
		t.Run(tt.action.String(), func(t *testing.T) {
			output := getActionSymbol(tt.action)
			if output != tt.expected {
				t.Errorf("getActionSymbol(%v) = %q, want %q", tt.action, output, tt.expected)
			}
		})
	}
}

